svg.script:
      let background = window.parent.document.getElementById('background');
      let box = window.parent.document.getElementById('box');
      let popup = (text) => {
         background.style.visibility = 'visible';
         box.style.visibility = 'visible';
         box.innerHTML = text;
      }

      let titulo = document.getElementById('titulo');
      titulo.text = "Texto aquí";
      titulo.addEventListener('mouseenter', function(){ titulo.style.opacity = 0.85; }, false);
      titulo.addEventListener('mouseleave', function(){ titulo.style.opacity = 1; }, false);

      let unal = document.getElementById('unal');
      unal.text = "Texto aquí";
      unal.addEventListener('mouseenter', function(){ unal.style.opacity = 0.85; }, false);
      unal.addEventListener('mouseleave', function(){ unal.style.opacity = 1; }, false);

      let ods3 = document.getElementById('ods3');
      ods3.text = "Texto aquí";
      ods3.addEventListener('mouseenter', function(){ ods3.style.opacity = 0.85; }, false);
      ods3.addEventListener('mouseleave', function(){ ods3.style.opacity = 1; }, false);

      let ods9 = document.getElementById('ods9');
      ods9.text = "Texto aquí";
      ods9.addEventListener('mouseenter', function(){ ods9.style.opacity = 0.85; }, false);
      ods9.addEventListener('mouseleave', function(){ ods9.style.opacity = 1; }, false);

      let goldenVision = document.getElementById('goldenVision');
      goldenVision.text = "Texto aquí";
      goldenVision.addEventListener('mouseenter', function(){ goldenVision.style.opacity = 0.85; }, false);
      goldenVision.addEventListener('mouseleave', function(){ goldenVision.style.opacity = 1; }, false);

      let antecedentes = document.getElementById('antecedentes');
      antecedentes.text = "Texto aquí";
      antecedentes.addEventListener('mouseenter', function(){ antecedentes.style.opacity = 0.7; }, false);
      antecedentes.addEventListener('mouseleave', function(){ antecedentes.style.opacity = 1; }, false);

      let actores = document.getElementById('actores');
      actores.text = "Texto aquí";
      actores.addEventListener('mouseenter', function(){ actores.style.opacity = 0.7; }, false);
      actores.addEventListener('mouseleave', function(){ actores.style.opacity = 1; }, false);

      let pestal = document.getElementById('pestal');
      pestal.addEventListener('mouseenter', function(){ pestal.style.opacity = 0.9; }, false);
      pestal.addEventListener('mouseleave', function(){ pestal.style.opacity = 1; }, false);

      let pestalP = document.getElementById('pestalP');
      pestalP.text = "En este aspecto podemos encontrar la guerra contra las drogas. En 1961 la ONU estableció la eliminación del consumo de la marihuana en 25 años. Las manifestantes en contra de esta propuesta buscan un cambio de perspectiva política. Las comunidades colombianas se han visto afectadas por la violencia y el narcotráfico en el país en cuestiones territoriales, haciendo que se desplacen hacia las ciudades principales de Colombia.";

      pestalP.addEventListener('mouseenter', function(){ pestalP.style.opacity = 0.7; pestal.style.opacity = 0.9; }, false);
      pestalP.addEventListener('mouseleave', function(){ pestalP.style.opacity = 1; pestal.style.opacity = 1; }, false);
      pestalP.addEventListener('click', function() { popup(pestalP.text); }, false);

      let pestalE = document.getElementById('pestalE');
      pestalE.text = "Según la consultora económica e-concept se generaron 100.000 empleos nuevos que superaron el recaudo fiscal de todo el sector agrícola. Según el exministro de Hacienda Juan Carlos Echeverry las exportaciones del cannabis medicinal oscilarían entre 2.300 y 17.700 millones de dólares. El recaudo  generado por esta industria podría ubicarse entre 1,2 y 3,5 billones de pesos.";

      pestalE.addEventListener('mouseenter', function(){ pestalE.style.opacity = 0.7; pestal.style.opacity = 0.9; }, false);
      pestalE.addEventListener('mouseleave', function(){ pestalE.style.opacity = 1; pestal.style.opacity = 1; }, false);
      pestalE.addEventListener('click', function() { popup(pestalE.text); }, false);

      let pestalS = document.getElementById('pestalS');
      pestalS.text = `La producción de cannabis con fines medicinales tiene un impacto positivo en la sociedad, pues no solo reduce el estigma que hay alrededor de la planta, también trae mejoras en materias de salud y economía que motivan a las personas a involucrarse con estos derivados desde el consumo hasta la formulación de proyectos.

      Si logra despegar como industria, este producto tendría impacto en el empleo rural, ya que es un cultivo intensivo que requiere de 10 a 17 personas por hectárea, a quienes se les pagarán todas sus prestaciones sociales de ley, dignificando el trabajo en el campo.`;
      pestalS.addEventListener('mouseenter', function(){ pestalS.style.opacity = 0.7; pestal.style.opacity = 0.9; }, false);
      pestalS.addEventListener('mouseleave', function(){ pestalS.style.opacity = 1; pestal.style.opacity = 1; }, false);
      pestalS.addEventListener('click', function() { popup(pestalS.text); }, false);

      let pestalT = document.getElementById('pestalT');
      pestalT.text = "En los últimos años se ha visto el desarrollo de tecnologías que apoyan la producción agrícola y que nos pueden apoyar en el desarrollo de nuestro proyecto como son la agricultura inteligente, la computación en la nube y el internet de las cosas.";

      pestalT.addEventListener('mouseenter', function(){ pestalT.style.opacity = 0.7; pestal.style.opacity = 0.9; }, false);
      pestalT.addEventListener('mouseleave', function(){ pestalT.style.opacity = 1; pestal.style.opacity = 1; }, false);
      pestalT.addEventListener('click', function() { popup(pestalT.text); }, false);

      let pestalA = document.getElementById('pestalA');
      pestalA.text = "El cannabis puede ayudar en el combate de la contaminación ambiental ya que cada hectárea absorbe entre 20 y 30 toneladas de CO2  del aire por año y una vez cosechado, cada tonelada fija en sus tejidos otros 325 kilos. Por otro lado, el cáñamo puede sustituir a varias materias primas ya que con las fibras de esta planta se pueden fabricar productos biodegradables.";

      pestalA.addEventListener('mouseenter', function(){ pestalA.style.opacity = 0.7; pestal.style.opacity = 0.9; }, false);
      pestalA.addEventListener('mouseleave', function(){ pestalA.style.opacity = 1; pestal.style.opacity = 1; }, false);
      pestalA.addEventListener('click', function() { popup(pestalA.text); }, false);

      let pestalL = document.getElementById('pestalL');
      pestalL.text = "Instituciones como el ICA y el INVIMA se encargan de monitorear y evaluar cada una de las etapas de la cadena de producción para garantizar la máxima calidad y el cumpliento estricto de los parámetros establecidos en la ley 8717 del 6 de julio de 2016, el decreto 613 del 10 de abril de 2017 y el decreto 811 del 23 de julio de 2021.";

      pestalL.addEventListener('mouseenter', function(){ pestalL.style.opacity = 0.7; pestal.style.opacity = 0.9; }, false);
      pestalL.addEventListener('mouseleave', function(){ pestalL.style.opacity = 1; pestal.style.opacity = 1; }, false);
      pestalL.addEventListener('click', function() { popup(pestalL.text); }, false);

      let solucion1 = document.getElementById('solucion1');
      solucion1.text = "Texto aquí";
      solucion1.addEventListener('mouseenter', function(){ solucion1.style.opacity = 0.7; }, false);
      solucion1.addEventListener('mouseleave', function(){ solucion1.style.opacity = 1; }, false);


      let solucion2 = document.getElementById('solucion2');
      solucion2.text = "Texto aquí";
      solucion2.addEventListener('mouseenter', function(){ solucion2.style.opacity = 0.7; }, false);
      solucion2.addEventListener('mouseleave', function(){ solucion2.style.opacity = 1; }, false);


      let solucion3 = document.getElementById('solucion3');
      solucion3.text = "Texto aquí";
      solucion3.addEventListener('mouseenter', function(){ solucion3.style.opacity = 0.7; }, false);
      solucion3.addEventListener('mouseleave', function(){ solucion3.style.opacity = 1; }, false);


      let expertos = document.getElementById('expertos');
      expertos.addEventListener('mouseenter', function(){ expertos.style.opacity = 0.9; }, false);
      expertos.addEventListener('mouseleave', function(){ expertos.style.opacity = 1; }, false);

      let experto1 = document.getElementById('experto1');
      experto1.text = "Jorge Ariel Martínez es un profesor asociado de la facultad de ciencias de la Universidad Nacional de Colombia, especialista en control de calidad y miembro del grupo de investigación en fitoquímica Giffungrupo. Su opinión sobre el desarrollo del proyecto desde su punto de vista farmacéutico, es una implementación de trazabilidad buscando una mejora en la calidad del producto con fines fitoterapéuticos.";

      experto1.addEventListener('mouseenter', function(){ experto1.style.opacity = 0.95; expertos.style.opacity = 0.9; }, false);
      experto1.addEventListener('mouseleave', function(){ experto1.style.opacity = 1; expertos.style.opacity = 1; }, false);
      experto1.addEventListener('click', function() { popup(experto1.text); }, false);

      let experto2 = document.getElementById('experto2');
      experto2.text = "Antonio Matic es un especialista experimentado en la industria de bienestar de la salud. Es licenciado de Portland State University y trabaja en ventas y soporte técnico de OpenTHC. Su aporte para la resolución del proyecto es brindarnos una guia del funcionamiento de su software para orientarnos en la aplicación real de la trazabilidad en un sistema de información";

      experto2.addEventListener('mouseenter', function(){ experto2.style.opacity = 0.95; expertos.style.opacity = 0.9; }, false);
      experto2.addEventListener('mouseleave', function(){ experto2.style.opacity = 1; expertos.style.opacity = 1; }, false);
      experto2.addEventListener('click', function() { popup(experto2.text); }, false);

      let matraz1 = document.getElementById('matraz1');
      matraz1.text = "Texto aquí";
      matraz1.addEventListener('mouseenter', function(){ matraz1.style.opacity = 0.7; }, false);
      matraz1.addEventListener('mouseleave', function(){ matraz1.style.opacity = 1; }, false);


      let matraz2 = document.getElementById('matraz2');
      matraz2.text = "Texto aquí";
      matraz2.addEventListener('mouseenter', function(){ matraz2.style.opacity = 0.7; }, false);
      matraz2.addEventListener('mouseleave', function(){ matraz2.style.opacity = 1; }, false);


      let problema = document.getElementById('problema');
      problema.text = "No hay recopilación de datos que apoye la toma de decisiones orientado a la mejora del banco de semillas y del sistema de elaboración de productos farmacéuticos, fitoterapéuticos, fórmulas magistrales y cosméticos.";

      problema.addEventListener('mouseenter', function(){ problema.style.opacity = 0.7; }, false);
      problema.addEventListener('mouseleave', function(){ problema.style.opacity = 1; }, false);
      problema.addEventListener('click', function() { popup(problema.text); }, false);

      let referencias = document.getElementById('referencias');
      referencias.text = `Cannabis Traza Software especializado. (2002). Trazabilidad en cannabis. Recuperado 26 de abril de 2022, de https://cannabistraza.com
True Trace. (2021, 7 octubre). Most Trusted in Cannabis Safety, Track and Trace Technology for Cannabis. StrainSecure. Recuperado 26 de abril de 2022, de https://strainsecure.com
OpenTHC. (2015). Open Source Cannabis Software. Recuperado 26 de abril de 2022, de https://openthc.com
Beltrán, G. (2021, 15 julio). Inicio - Golden Vision - Genbank. Golden Vision - Genbank. http://gvgenbank.com`;

      referencias.addEventListener('mouseenter', function(){ referencias.style.opacity = 0.7; }, false);
      referencias.addEventListener('mouseleave', function(){ referencias.style.opacity = 1; }, false);
      referencias.addEventListener('click', function() { popup(referencias.text); }, false);

      let qr = document.getElementById('qr');
      qr.addEventListener('mouseenter', function(){ qr.style.opacity = 0.7; }, false);
      qr.addEventListener('mouseleave', function(){ qr.style.opacity = 1; }, false);
      qr.addEventListener('click', function() { window.open('https://golden-vision-genbank.github.io/references/', '_blank').focus(); }, false);
